const express = require('express');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/dataQueryService', {
  useNewUrlParser: true,
  useUnifiedTopology: true,
});

// Define a sample schema and model
const SampleSchema = new mongoose.Schema({
  name: String,
  age: Number,
  email: String,
});
const SampleModel = mongoose.model('Sample', SampleSchema);

// Middleware to sanitize input (simple example)
function sanitizeInput(input) {
  return JSON.parse(JSON.stringify(input));
}

app.post('/query', async (req, res) => {
  try {
    const filters = sanitizeInput(req.body);
    const results = await SampleModel.find(filters).exec();
    res.json(results);
  } catch (error) {
    res.status(500).json({ error: 'Internal Server Error' });
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});